import {
  ASSOCIATED_TOKEN_PROGRAM_ID,
  createInitializeMintInstruction,
  getMinimumBalanceForRentExemptMint,
  MINT_SIZE,
  TOKEN_PROGRAM_ID,
} from "@solana/spl-token";
import {
  createCreateMetadataAccountV3Instruction,
  PROGRAM_ID as TOKEN_METADATA_PROGRAM_ID,
} from "@metaplex-foundation/mpl-token-metadata";
import { Connection, Keypair, PublicKey, SystemProgram, Transaction } from "@solana/web3.js";
import type { WalletContextState } from "@solana/wallet-adapter-react";

export async function createMintAndMetadata(args: {
  connection: Connection;
  wallet: WalletContextState;
  name: string;
  symbol: string;
  uri: string;
}): Promise<PublicKey> {
  if (!args.wallet.publicKey) throw new Error("Connect a wallet first.");
  const mint = Keypair.generate();
  const rent = await getMinimumBalanceForRentExemptMint(args.connection);
  const [metadata] = PublicKey.findProgramAddressSync(
    [Buffer.from("metadata"), TOKEN_METADATA_PROGRAM_ID.toBuffer(), mint.publicKey.toBuffer()],
    TOKEN_METADATA_PROGRAM_ID,
  );

  const tx = new Transaction().add(
    SystemProgram.createAccount({
      fromPubkey: args.wallet.publicKey,
      newAccountPubkey: mint.publicKey,
      space: MINT_SIZE,
      lamports: rent,
      programId: TOKEN_PROGRAM_ID,
    }),
    createInitializeMintInstruction(mint.publicKey, 6, args.wallet.publicKey, null),
    createCreateMetadataAccountV3Instruction(
      {
        metadata,
        mint: mint.publicKey,
        mintAuthority: args.wallet.publicKey,
        payer: args.wallet.publicKey,
        updateAuthority: args.wallet.publicKey,
      },
      {
        createMetadataAccountArgsV3: {
          data: {
            name: args.name,
            symbol: args.symbol,
            uri: args.uri,
            sellerFeeBasisPoints: 0,
            creators: [{ address: args.wallet.publicKey, verified: true, share: 100 }],
            collection: null,
            uses: null,
          },
          isMutable: false,
          collectionDetails: null,
        },
      },
    ),
  );

  const signature = await args.wallet.sendTransaction(tx, args.connection, { signers: [mint] });
  await args.connection.confirmTransaction(signature, "confirmed");
  return mint.publicKey;
}

export const LAMPORTS_PER_SOL_BIGINT = 1_000_000_000n;
export const TOKEN_SCALE = 1_000_000n;

export function formatUnits(value: bigint, scale: bigint, digits = 4): string {
  const whole = value / scale;
  const fraction = (value % scale).toString().padStart(scale.toString().length - 1, "0").slice(0, digits);
  return `${whole.toLocaleString()}${digits ? `.${fraction}` : ""}`;
}

export function parseDecimal(value: string, decimals: number): bigint {
  const [whole = "0", fraction = ""] = value.trim().split(".");
  const padded = (fraction + "0".repeat(decimals)).slice(0, decimals);
  return BigInt(whole || "0") * 10n ** BigInt(decimals) + BigInt(padded || "0");
}

export function shorten(address: string): string {
  return `${address.slice(0, 5)}…${address.slice(-5)}`;
}

"use client";

import { AnchorProvider, Idl, Program, type Wallet } from "@coral-xyz/anchor";
import { useAnchorWallet, useConnection } from "@solana/wallet-adapter-react";
import { PublicKey, SystemProgram, Transaction, VersionedTransaction } from "@solana/web3.js";
import { useMemo } from "react";
import idl from "@/idl/core_launchpad.json";

const readOnlyWallet: Wallet = {
  publicKey: SystemProgram.programId,
  async signTransaction<T extends Transaction | VersionedTransaction>(_tx: T): Promise<T> {
    throw new Error("Connect a wallet before sending a transaction.");
  },
  async signAllTransactions<T extends Transaction | VersionedTransaction>(_txs: T[]): Promise<T[]> {
    throw new Error("Connect a wallet before sending a transaction.");
  },
};

export function useLaunchpadProgram(): Program {
  const connectedWallet = useAnchorWallet();
  const { connection } = useConnection();
  const address = process.env.NEXT_PUBLIC_PROGRAM_ID ?? (idl as { address: string }).address;
  return useMemo(() => {
    const provider = new AnchorProvider(connection, connectedWallet ?? readOnlyWallet, { commitment: "confirmed" });
    return new Program({ ...(idl as Idl), address }, provider);
  }, [address, connectedWallet, connection]);
}

export function programId(): PublicKey {
  return new PublicKey(process.env.NEXT_PUBLIC_PROGRAM_ID ?? (idl as { address: string }).address);
}
